import java.lang.Math

/**
 * Segment Tree implementation for Range Maximum Query (RMQ) and Point Update (Max).
 * Operates on 1-based index space [1, V_MAX].
 */
class SegmentTree(private val V_MAX: Int) {
    // We use Long.MIN_VALUE / 2 as negative infinity to prevent overflow during addition
    private val NEG_INF = Long.MIN_VALUE / 2
    private val tree = Array(4 * V_MAX + 4) { NEG_INF }

    /**
     * Updates the value at a specific index 'idx' to be max(current_value, newVal).
     */
    fun update(idx: Int, newVal: Long) {
        updateRec(1, 1, V_MAX, idx, newVal)
    }

    private fun updateRec(node: Int, start: Int, end: Int, idx: Int, newVal: Long) {
        if (start == end) {
            // Leaf node
            tree[node] = Math.max(tree[node], newVal)
            return
        }

        val mid = start + (end - start) / 2
        if (idx <= mid) {
            updateRec(2 * node, start, mid, idx, newVal)
        } else {
            updateRec(2 * node + 1, mid + 1, end, idx, newVal)
        }
        // Internal node update: max of children
        tree[node] = Math.max(tree[2 * node], tree[2 * node + 1])
    }

    /**
     * Queries the maximum value in the range [L, R].
     */
    fun query(L: Int, R: Int): Long {
        if (L > R) return NEG_INF
        return queryRec(1, 1, V_MAX, L, R)
    }

    private fun queryRec(node: Int, start: Int, end: Int, L: Int, R: Int): Long {
        if (R < start || end < L) {
            // Range outside query bounds
            return NEG_INF
        }
        if (L <= start && end <= R) {
            // Current segment is fully within query range
            return tree[node]
        }

        val mid = start + (end - start) / 2
        val p1 = queryRec(2 * node, start, mid, L, R)
        val p2 = queryRec(2 * node + 1, mid + 1, end, L, R)

        return Math.max(p1, p2)
    }
}

