    if (N == 0) return 0L

    // Max value constraint for array indexing (10^5)
    val V_MAX = 100000 

    // Up[i]: Max score ending at i with an increasing transition (j < i, nums[j] < nums[i])
    val Up = LongArray(N)
    // Down[i]: Max score ending at i with a decreasing transition (j < i, nums[j] > nums[i])
    val Down = LongArray(N)

    // ST_Up stores max(Up[j]) indexed by nums[j], for j <= i-k. Used when calculating Down[i].
    val ST_Up = SegmentTree(V_MAX)
    // ST_Down stores max(Down[j]) indexed by nums[j], for j <= i-k. Used when calculating Up[i].
    val ST_Down = SegmentTree(V_MAX)

    var maxScore = 0L

    for (i in 0 until N) {
        val currentVal = nums[i]

