/**
 * A helper class for a Segment Tree supporting Range Maximum Query (RMQ) and Point Update.
 * The tree is 1-indexed based on the values (1 to V_max).
 */
private class SegmentTree(private val size: Int) {
    private val tree: LongArray
    private val arraySize: Int

    init {
        // Size of the tree array is typically 4 * arraySize for safety
        arraySize = size
        tree = LongArray(4 * size + 1) { 0L }
    }

    /**
     * Updates the value at a specific index (value v) to max(current value, newValue).
     * @param v The 1-based index (value in nums).
     * @param newValue The score to update with.
     */
    fun update(v: Int, newValue: Long) {
        updateRecursive(1, 1, arraySize, v, newValue)
    }

    private fun updateRecursive(node: Int, start: Int, end: Int, idx: Int, newValue: Long) {
        if (start == end) {
            // Leaf node: store the maximum score seen so far for this value
            tree[node] = max(tree[node], newValue)
            return
        }

        val mid = start + (end - start) / 2
        if (idx <= mid) {
            updateRecursive(2 * node, start, mid, idx, newValue)
        } else {
            updateRecursive(2 * node + 1, mid + 1, end, idx, newValue)
        }
        // Internal node update: store the maximum of its children
        tree[node] = max(tree[2 * node], tree[2 * node + 1])
    }

    /**
     * Queries the maximum value in the range [l, r] (inclusive).
     * @param l Left boundary (1-based).
     * @param r Right boundary (1-based).
     * @return The maximum score in the range, or 0 if the range is invalid.
     */
    fun query(l: Int, r: Int): Long {
        if (l > r || l > arraySize || r < 1) return 0L
        val actualL = max(1, l)
        val actualR = minOf(arraySize, r)
        return queryRecursive(1, 1, arraySize, actualL, actualR)
    }

    private fun queryRecursive(node: Int, start: Int, end: Int, l: Int, r: Int): Long {
        // Range represented by node is completely outside the given range
        if (r < start || end < l) {
            return 0L
        }
        // Range represented by node is completely inside the given range
        if (l <= start && end <= r) {
            return tree[node]
        }

        val mid = start + (end - start) / 2
        val p1 = queryRecursive(2 * node, start, mid, l, r)
        val p2 = queryRecursive(2 * node + 1, mid + 1, end, l, r)
        return max(p1, p2)
    }
}

